//! Spec-compliance tests: Continuous Section Inheritance Edge Cases
//! (ISO 29500-1 section 17.6.22)
//!
//! Per ISO 29500-1 section 17.6.22: continuous section breaks do not start a new page.
//! When a continuous section omits page-level properties, those properties are
//! inherited from the preceding section.
//!
//! These tests probe edge cases: chained continuous sections, non-continuous
//! breaks in the chain, page size inheritance, and gutter/distance inheritance.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/section-continuous-edge/create_fixtures.py`.

use stemma::{BlockNode, CanonDoc, SectionProperties, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/section-continuous-edge";

// -- helpers ----------------------------------------------------------------

/// Collect all mid-document section properties (from pPr/sectPr).
fn section_paragraphs(doc: &CanonDoc) -> Vec<&SectionProperties> {
    let mut props = Vec::new();
    collect_section_props_tracked(&doc.blocks, &mut props);
    props
}

fn collect_section_props_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a SectionProperties>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_section_props_bare<'a>(blocks: &'a [BlockNode], out: &mut Vec<&'a SectionProperties>) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

// ==========================================================================
// 1. CHAINED CONTINUOUS SECTIONS
// ==========================================================================

/// ISO 29500-1 section 17.6.22: Chained continuous sections propagate
/// inherited values forward.
///
/// S1(nextPage): margins top=1440, left=1800, bottom=1440, right=1800,
///               pgSz 12240x15840
/// S2(continuous): only left=720 declared, no pgSz
/// S3(continuous, body-level): NO pgMar at all, no pgSz
///
/// After propagation:
/// - S2 should have left=720 (own), top/bottom=1440, right=1800 (from S1),
///   page_width=12240, page_height=15840 (from S1)
/// - S3 should inherit ALL from S2's enriched state (including values that
///   S2 itself inherited from S1)
#[test]
fn spec_chained_continuous_s2_inherits_from_s1() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "chained-continuous-sections");

    let section_props = section_paragraphs(&doc);
    assert_eq!(
        section_props.len(),
        2,
        "should have 2 mid-document sections (S1, S2), got {}",
        section_props.len()
    );

    // S1: nextPage with full margins and page size
    let s1 = section_props[0];
    assert_eq!(
        s1.section_type,
        Some(stemma::domain::SectionType::NextPage),
        "S1 should be nextPage"
    );
    assert_eq!(s1.margin_top, Some(1440), "S1 margin_top");
    assert_eq!(s1.margin_left, Some(1800), "S1 margin_left");
    assert_eq!(s1.margin_bottom, Some(1440), "S1 margin_bottom");
    assert_eq!(s1.margin_right, Some(1800), "S1 margin_right");
    assert_eq!(s1.page_width, Some(12240), "S1 page_width");
    assert_eq!(s1.page_height, Some(15840), "S1 page_height");

    // S2: continuous, only left=720 declared
    let s2 = section_props[1];
    assert_eq!(
        s2.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "S2 should be continuous"
    );

    // S2 keeps its own left=720
    assert_eq!(
        s2.margin_left,
        Some(720),
        "S2 margin_left should be 720 (own), got {:?}",
        s2.margin_left
    );

    // S2 inherits the rest from S1
    assert_eq!(
        s2.margin_top,
        Some(1440),
        "S2 margin_top should inherit 1440 from S1, got {:?}",
        s2.margin_top
    );
    assert_eq!(
        s2.margin_bottom,
        Some(1440),
        "S2 margin_bottom should inherit 1440 from S1, got {:?}",
        s2.margin_bottom
    );
    assert_eq!(
        s2.margin_right,
        Some(1800),
        "S2 margin_right should inherit 1800 from S1, got {:?}",
        s2.margin_right
    );

    // S2 inherits page size from S1
    assert_eq!(
        s2.page_width,
        Some(12240),
        "S2 page_width should inherit 12240 from S1, got {:?}",
        s2.page_width
    );
    assert_eq!(
        s2.page_height,
        Some(15840),
        "S2 page_height should inherit 15840 from S1, got {:?}",
        s2.page_height
    );
}

/// ISO 29500-1 section 17.6.22: S3 (body-level, continuous) inherits from
/// S2's ENRICHED state, not just S2's declared values.
///
/// The key behavior: `prev_props = Some(sp.clone())` clones S2 AFTER
/// inheritance, so S3 gets S2's enriched properties (which include values
/// inherited from S1).
#[test]
fn spec_chained_continuous_s3_inherits_enriched_s2() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "chained-continuous-sections");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (S3)");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "S3 should be continuous"
    );

    // S3 inherits all margins from S2's enriched state:
    // left=720 (S2's own), top/bottom=1440 (S1->S2), right=1800 (S1->S2)
    assert_eq!(
        body_sp.margin_left,
        Some(720),
        "S3 margin_left should inherit 720 from S2 (S2's own), got {:?}",
        body_sp.margin_left
    );
    assert_eq!(
        body_sp.margin_top,
        Some(1440),
        "S3 margin_top should inherit 1440 (S1->S2->S3), got {:?}",
        body_sp.margin_top
    );
    assert_eq!(
        body_sp.margin_bottom,
        Some(1440),
        "S3 margin_bottom should inherit 1440 (S1->S2->S3), got {:?}",
        body_sp.margin_bottom
    );
    assert_eq!(
        body_sp.margin_right,
        Some(1800),
        "S3 margin_right should inherit 1800 (S1->S2->S3), got {:?}",
        body_sp.margin_right
    );

    // S3 inherits page size from S2's enriched state (originally from S1)
    assert_eq!(
        body_sp.page_width,
        Some(12240),
        "S3 page_width should inherit 12240 (S1->S2->S3), got {:?}",
        body_sp.page_width
    );
    assert_eq!(
        body_sp.page_height,
        Some(15840),
        "S3 page_height should inherit 15840 (S1->S2->S3), got {:?}",
        body_sp.page_height
    );
}

// ==========================================================================
// 2. NON-CONTINUOUS BREAKS CHAIN
// ==========================================================================

/// ISO 29500-1 section 17.6.22: A nextPage section does not inherit
/// from preceding sections and resets the chain.
///
/// S1(nextPage, 1440 margins) -> S2(continuous, no margins, inherits S1) ->
/// S3(nextPage, 2880 margins, landscape) -> S4(continuous, no margins)
///
/// S4 should inherit from S3 (2880 margins, landscape), NOT from S2 or S1.
#[test]
fn spec_non_continuous_s2_inherits_from_s1() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "non-continuous-breaks-chain");

    let section_props = section_paragraphs(&doc);
    assert_eq!(
        section_props.len(),
        3,
        "should have 3 mid-document sections (S1, S2, S3), got {}",
        section_props.len()
    );

    // S2 (continuous) should inherit margins from S1 (1440)
    let s2 = section_props[1];
    assert_eq!(
        s2.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "S2 should be continuous"
    );
    assert_eq!(
        s2.margin_top,
        Some(1440),
        "S2 margin_top should inherit 1440 from S1, got {:?}",
        s2.margin_top
    );
    assert_eq!(
        s2.margin_left,
        Some(1440),
        "S2 margin_left should inherit 1440 from S1, got {:?}",
        s2.margin_left
    );
}

/// S3 (nextPage) keeps its own margins and does NOT inherit.
#[test]
fn spec_non_continuous_s3_keeps_own_values() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "non-continuous-breaks-chain");

    let section_props = section_paragraphs(&doc);
    let s3 = section_props[2];

    assert_eq!(
        s3.section_type,
        Some(stemma::domain::SectionType::NextPage),
        "S3 should be nextPage"
    );
    assert_eq!(
        s3.margin_top,
        Some(2880),
        "S3 margin_top should be 2880 (own), got {:?}",
        s3.margin_top
    );
    assert_eq!(
        s3.margin_left,
        Some(2880),
        "S3 margin_left should be 2880 (own), got {:?}",
        s3.margin_left
    );
    assert_eq!(
        s3.page_width,
        Some(15840),
        "S3 page_width should be 15840 (landscape), got {:?}",
        s3.page_width
    );
    assert_eq!(
        s3.page_height,
        Some(12240),
        "S3 page_height should be 12240 (landscape), got {:?}",
        s3.page_height
    );
    assert_eq!(
        s3.orientation,
        Some(stemma::domain::PageOrientation::Landscape),
        "S3 orientation should be Landscape, got {:?}",
        s3.orientation
    );
}

/// S4 (continuous, body-level) inherits from S3 (nextPage, 2880 margins,
/// landscape), NOT from S2 or S1.
///
/// This confirms that nextPage sections reset the prev_props chain:
/// S4 sees S3's values because S3 is the most recent section in the
/// iteration order, regardless of S3 being non-continuous.
#[test]
fn spec_non_continuous_s4_inherits_from_s3_not_s2() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "non-continuous-breaks-chain");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (S4)");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "S4 should be continuous"
    );

    // S4 inherits from S3 (2880 margins), NOT S1 (1440) or S2 (inherited 1440)
    assert_eq!(
        body_sp.margin_top,
        Some(2880),
        "S4 margin_top should inherit 2880 from S3, got {:?}",
        body_sp.margin_top
    );
    assert_eq!(
        body_sp.margin_left,
        Some(2880),
        "S4 margin_left should inherit 2880 from S3, got {:?}",
        body_sp.margin_left
    );
    assert_eq!(
        body_sp.margin_bottom,
        Some(2880),
        "S4 margin_bottom should inherit 2880 from S3, got {:?}",
        body_sp.margin_bottom
    );
    assert_eq!(
        body_sp.margin_right,
        Some(2880),
        "S4 margin_right should inherit 2880 from S3, got {:?}",
        body_sp.margin_right
    );

    // S4 inherits page size and orientation from S3 (landscape)
    assert_eq!(
        body_sp.page_width,
        Some(15840),
        "S4 page_width should inherit 15840 from S3, got {:?}",
        body_sp.page_width
    );
    assert_eq!(
        body_sp.page_height,
        Some(12240),
        "S4 page_height should inherit 12240 from S3, got {:?}",
        body_sp.page_height
    );
    assert_eq!(
        body_sp.orientation,
        Some(stemma::domain::PageOrientation::Landscape),
        "S4 orientation should inherit Landscape from S3, got {:?}",
        body_sp.orientation
    );

    // S4 inherits gutter from S3
    assert_eq!(
        body_sp.gutter,
        Some(360),
        "S4 gutter should inherit 360 from S3, got {:?}",
        body_sp.gutter
    );

    // S4 inherits header/footer distances from S3
    assert_eq!(
        body_sp.header_distance,
        Some(1440),
        "S4 header_distance should inherit 1440 from S3, got {:?}",
        body_sp.header_distance
    );
    assert_eq!(
        body_sp.footer_distance,
        Some(1440),
        "S4 footer_distance should inherit 1440 from S3, got {:?}",
        body_sp.footer_distance
    );
}

// ==========================================================================
// 3. PAGE SIZE INHERITANCE
// ==========================================================================

/// ISO 29500-1 section 17.6.22: Continuous section without pgSz inherits
/// page_width and page_height from the preceding section.
///
/// S1(nextPage): pgSz 12240x15840 (Letter), margins 1440
/// S2(continuous, body-level): margins 720, NO pgSz element at all
///
/// S2 should inherit page_width=12240, page_height=15840 from S1,
/// while keeping its own margins (720).
#[test]
fn spec_page_size_inherited_when_absent() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "page-size-inheritance");

    let section_props = section_paragraphs(&doc);
    assert_eq!(
        section_props.len(),
        1,
        "should have 1 mid-document section (S1), got {}",
        section_props.len()
    );

    // S1 has explicit page size
    let s1 = section_props[0];
    assert_eq!(s1.page_width, Some(12240), "S1 page_width");
    assert_eq!(s1.page_height, Some(15840), "S1 page_height");

    // S2 (body-level, continuous)
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (S2)");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "S2 should be continuous"
    );

    // S2 keeps its own margins
    assert_eq!(
        body_sp.margin_top,
        Some(720),
        "S2 margin_top should be 720 (own), got {:?}",
        body_sp.margin_top
    );
    assert_eq!(
        body_sp.margin_left,
        Some(720),
        "S2 margin_left should be 720 (own), got {:?}",
        body_sp.margin_left
    );

    // S2 inherits page size from S1
    assert_eq!(
        body_sp.page_width,
        Some(12240),
        "S2 page_width should inherit 12240 from S1, got {:?}",
        body_sp.page_width
    );
    assert_eq!(
        body_sp.page_height,
        Some(15840),
        "S2 page_height should inherit 15840 from S1, got {:?}",
        body_sp.page_height
    );
}

// ==========================================================================
// 4. GUTTER AND HEADER/FOOTER DISTANCE INHERITANCE
// ==========================================================================

/// ISO 29500-1 section 17.6.22: Continuous section inherits gutter and
/// header/footer distances when those attributes are absent from pgMar.
///
/// S1(nextPage): gutter=720, header=720, footer=720
/// S2(continuous, body-level): pgMar has top/left/bottom/right but NO
///   gutter/header/footer attributes
///
/// S2 should inherit gutter=720, header_distance=720, footer_distance=720.
#[test]
fn spec_gutter_inherited_when_absent() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "gutter-and-distances");

    let section_props = section_paragraphs(&doc);
    assert_eq!(
        section_props.len(),
        1,
        "should have 1 mid-document section (S1), got {}",
        section_props.len()
    );

    // S1 has gutter=720
    let s1 = section_props[0];
    assert_eq!(
        s1.gutter,
        Some(720),
        "S1 gutter should be 720, got {:?}",
        s1.gutter
    );

    // S2 (body-level, continuous)
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (S2)");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "S2 should be continuous"
    );

    // S2 inherits gutter from S1
    assert_eq!(
        body_sp.gutter,
        Some(720),
        "S2 gutter should inherit 720 from S1, got {:?}",
        body_sp.gutter
    );
}

/// Header and footer distances are inherited when absent from the
/// continuous section's pgMar.
#[test]
fn spec_header_footer_distance_inherited_when_absent() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "gutter-and-distances");

    let section_props = section_paragraphs(&doc);
    let s1 = section_props[0];
    assert_eq!(s1.header_distance, Some(720), "S1 header_distance");
    assert_eq!(s1.footer_distance, Some(720), "S1 footer_distance");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (S2)");

    // S2 inherits header/footer distances from S1
    assert_eq!(
        body_sp.header_distance,
        Some(720),
        "S2 header_distance should inherit 720 from S1, got {:?}",
        body_sp.header_distance
    );
    assert_eq!(
        body_sp.footer_distance,
        Some(720),
        "S2 footer_distance should inherit 720 from S1, got {:?}",
        body_sp.footer_distance
    );
}

/// S2's own margins (top/left/bottom/right) should be preserved even
/// though gutter/distances are inherited.
#[test]
fn spec_gutter_distances_own_margins_preserved() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "gutter-and-distances");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (S2)");

    // S2 keeps its own margins
    assert_eq!(
        body_sp.margin_top,
        Some(1440),
        "S2 margin_top should be 1440 (own), got {:?}",
        body_sp.margin_top
    );
    assert_eq!(
        body_sp.margin_left,
        Some(1440),
        "S2 margin_left should be 1440 (own), got {:?}",
        body_sp.margin_left
    );
    assert_eq!(
        body_sp.margin_bottom,
        Some(1440),
        "S2 margin_bottom should be 1440 (own), got {:?}",
        body_sp.margin_bottom
    );
    assert_eq!(
        body_sp.margin_right,
        Some(1440),
        "S2 margin_right should be 1440 (own), got {:?}",
        body_sp.margin_right
    );
}
